// ─────────────────────────────────────────────────────────────────────────
//  Weapon Skills (Ashes of War).
//
//  name · fp (raw, e.g. "0 (2)" = base (follow-up/charged) cost) · armaments
//  (which weapons can use it; "specific armaments" = innate to a unique weapon)
//  · effect. Icons: /icons/weapon-skills/<id>.png.
//
//  Source: eldenringnightreign.wiki.fextralife.com/Weapon+Skills
// ─────────────────────────────────────────────────────────────────────────

export interface WeaponSkill {
  /** Slug + icon key, e.g. "lions-claw" → /icons/weapon-skills/lions-claw.png. */
  id: string;
  name: string;
  /** FP cost as shown on the wiki (raw string; may include a follow-up cost). */
  fp: string;
  /** Compatible armament types. */
  armaments: string;
  effect: string;
}

